- Significant amount of interest: total interest earned ≥ 500,000;
- Minimal threshold: interest rate > 1%;
- Notable financial threshold = significant amount of interest.

sql:
SELECT AVG(historical_rate) AS average_historical_rate
FROM historical_data
WHERE instrument_id = 0;

SELECT AVG(f.face_value) AS average_face_value
FROM financial_instruments f
INNER JOIN reports r ON f.instrument_id = r.instrument_id;

